content.problemStatement:
* You can create an empty `json` object and use `push_back()` to insert other JSON objects.
* When `push_back()` is used on an empty `json` object, it automatically becomes a JSON array.
* Use `ofstream` to write the data to a file.
* Use `.dump(4)` to format the output with indentation for better readability.
* Always check if the file is successfully opened before writing.

---

**Example:** Write Multiple JSON Objects to a File Using `push_back()`

```cpp
#include 
#include 
#include 
using json = nlohmann::json;

using namespace std;

int main() {
    // Creating individual JSON product objects
    json product1 = {
        {"id", 101},
        {"name", "Laptop"},
        {"price", 74999},
        {"tags", {"electronics", "computer"}}
    };

    json product2 = {
        {"id", 102},
        {"name", "Smartphone"},
        {"price", 39999},
        {"tags", {"electronics", "mobile"}}
    };

    json product3 = {
        {"id", 103},
        {"name", "Tablet"},
        {"price", 29999},
        {"tags", {"electronics", "portable"}}
    };

    // Start with an empty JSON object and push_back items
    json productList;
    productList.push_back(product1);
    productList.push_back(product2);
    productList.push_back(product3);

    // Write the JSON array to a file
    ofstream file("products.json");
    if (file.is_open()) {
        file << productList.dump(4); // Pretty-print with 4-space indentation
        file.close();
        cout << "Multiple JSON objects written to file successfully.\n";
    } else {
        cout << "Unable to open file for writing.\n";
    }

    return 0;
}
```

